# Static input
input_str = "i love programming love"

# Dictionary to store frequency
freq = {}

# Count frequency
for ch in input_str:
    if ch != ' ':  # ignore spaces
        if ch in freq:
            freq[ch] += 1
        else:
            freq[ch] = 1

# Print result
for key, value in freq.items():
    print(f"{key}={value}", end=", ")
